import type { Tutorial } from '@/engine/types';
import { curriculum } from './curriculum';
import { lessons } from './lessons';
import { images } from './images.manifest';
import { claudeCodeDiagrams } from './diagrams/index';
import { claudeCodeWidgets } from './widgets/index';

/**
 * Tutorial-scoped asset resolution. The engine never hardcodes asset paths — each tutorial
 * exposes its own images by id, so two tutorials can never collide. Add a PNG to ./assets/
 * (generated by the gemini-image skill) and reference it from an `image` block by its id.
 */
const assetModules = import.meta.glob<string>('./assets/*.{png,jpg,jpeg,svg,webp}', {
  eager: true,
  query: '?url',
  import: 'default',
});

const assets: Record<string, string> = {};
for (const [path, url] of Object.entries(assetModules)) {
  const id = path.split('/').pop()!.replace(/\.[^.]+$/, '');
  assets[id] = url;
}

export const claudeCodeTutorial: Tutorial = {
  id: 'claude-code',
  title: 'Claude Code, Taught',
  blurb: 'From the agentic loop to building real skills, agents, and connectors.',
  modules: curriculum,
  lessons,
  images,
  assets,
  diagrams: claudeCodeDiagrams,
  widgets: claudeCodeWidgets,
};
